mapper.update:
UPDATE remote_control_sessions
SET status = #{status}
WHERE id = #{id}
  AND customer_id = #{customerId}

UPDATE remote_control_sessions
SET
    webrtc_offer = #{webrtcOffer},
    webrtc_answer = #{webrtcAnswer},
    ice_candidates = #{iceCandidates}
WHERE id = #{id}
  AND customer_id = #{customerId}

UPDATE remote_control_sessions
SET
    status = 'CONNECTED',
    connected_at = #{connectedAt},
    remote_address = #{remoteAddress}
WHERE id = #{id}
  AND customer_id = #{customerId}

UPDATE remote_control_sessions
SET
    status = 'DISCONNECTED',
    ended_at = #{endedAt},
    duration_seconds = #{durationSeconds}
WHERE id = #{id}
  AND customer_id = #{customerId}

UPDATE remote_control_sessions
SET
    status = 'ERROR',
    error_message = #{errorMessage},
    ended_at = #{endedAt}
WHERE id = #{id}
  AND customer_id = #{customerId}

mapper.delete:
DELETE FROM remote_control_sessions
WHERE id = #{id}
  AND customer_id = #{customerId}

DELETE FROM remote_control_sessions
WHERE customer_id = #{customerId}
  AND status IN ('DISCONNECTED', 'ERROR')
  AND ended_at < #{beforeDate}
